mapper.select:
SELECT dc.id, dc.document_id, dc.chunk_index, dc.section_label, dc.content_text, dc.content_summary, dc.start_offset, dc.end_offset, dc.entity_list, dc.embedding_model, dc.content_hash, dc.created_at, dc.updated_at, 1 - (dc.embedding_vector <=> #{vector}::vector) AS similarity_score FROM document_chunks dc JOIN documents d ON dc.document_id = d.id WHERE d.document_status = 'INDEXED' AND dc.document_id IN
#{docId}
ORDER BY dc.embedding_vector <=> #{vector}::vector LIMIT #{topK}
